import React, { createContext, useState, useEffect, useMemo, useContext } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [isLoading, setIsLoading] = useState(true);
  const [userToken, setUserToken] = useState(null);
  const [userData, setUserData] = useState(null);

  useEffect(() => {
    // Check for existing session on app startup
    const bootstrapAsync = async () => {
      let token = null;
      let user = null;
      try {
        token = await AsyncStorage.getItem('userToken');
        const userJson = await AsyncStorage.getItem('userData');
        if (userJson) {
          user = JSON.parse(userJson);
        }
      } catch (e) {
        // Restoring token failed
        console.error('Failed to restore session:', e);
      } finally {
        setUserToken(token);
        setUserData(user);
        setIsLoading(false);
      }
    };

    bootstrapAsync();
  }, []);

  const authContext = useMemo(
    () => ({
      isLoading,
      userToken,
      userData,
      signIn: async (username, password) => {
        setIsLoading(true);
        try {
          // Simulate an API call for login
          await new Promise(resolve => setTimeout(resolve, 1500)); // Simulate network delay

          if (username === 'user' && password === 'password') {
            const token = 'dummy-auth-token-123'; // Replace with actual token from API
            const user = { id: '1', username: username, email: `${username}@example.com` }; // Replace with actual user data from API

            await AsyncStorage.setItem('userToken', token);
            await AsyncStorage.setItem('userData', JSON.stringify(user));

            setUserToken(token);
            setUserData(user);
          } else {
            throw new Error('Invalid credentials');
          }
        } catch (e) {
          console.error('Login error:', e);
          // Handle specific error messages from API, e.g., display to user
          // For simplicity, just log for now, actual Alert is handled in LoginScreen
          setUserToken(null);
          setUserData(null);
          throw e; // Re-throw to be caught by the screen for Alert
        } finally {
          setIsLoading(false);
        }
      },
      signUp: async (username, password, email) => {
        setIsLoading(true);
        try {
          // Simulate an API call for registration
          await new Promise(resolve => setTimeout(resolve, 1500)); // Simulate network delay

          // Simulate successful registration, usually returns a token and user data
          const token = 'dummy-auth-token-456'; // Replace with actual token from API
          const user = { id: '2', username: username, email: email || `${username}@example.com` }; // Replace with actual user data from API

          await AsyncStorage.setItem('userToken', token);
          await AsyncStorage.setItem('userData', JSON.stringify(user));

          setUserToken(token);
          setUserData(user);
        } catch (e) {
          console.error('Signup error:', e);
          // Handle specific error messages from API
          setUserToken(null);
          setUserData(null);
          throw e; // Re-throw to be caught by the screen for Alert
        } finally {
          setIsLoading(false);
        }
      },
      signOut: async () => {
        setIsLoading(true);
        try {
          await AsyncStorage.removeItem('userToken');
          await AsyncStorage.removeItem('userData');
        } catch (e) {
          console.error('Sign out error:', e);
        } finally {
          setUserToken(null);
          setUserData(null);
          setIsLoading(false);
        }
      },
    }),
    [isLoading, userToken, userData]
  );

  return (
    <AuthContext.Provider value={authContext}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  return useContext(AuthContext);
};

